{
  "mode": "method",
  "tests": [
    {
      "name": "test_checkpoint_screening_not_visible_before_activation",
      "input": {
        "challengeStatus": "inactive"
      },
      "output": {
        "checkpointScreeningVisible": false,
        "screeningPhasesVisible": false
      },
      "notes": "Validates that checkpoint screening and screening phases are not visible when the challenge is inactive."
    },
    {
      "name": "test_checkpoint_screening_visible_after_activation",
      "input": {
        "challengeStatus": "active"
      },
      "output": {
        "checkpointScreeningVisible": true,
        "screeningPhasesVisible": true
      },
      "notes": "Checks that checkpoint screening and screening phases become visible after the challenge is activated."
    },
    {
      "name": "test_multiple_challenges_inactive",
      "input": [
        { "challengeStatus": "inactive" },
        { "challengeStatus": "inactive" }
      ],
      "output": [
        { "checkpointScreeningVisible": false, "screeningPhasesVisible": false },
        { "checkpointScreeningVisible": false, "screeningPhasesVisible": false }
      ],
      "notes": "Ensures multiple inactive challenges do not show checkpoint screening or phases."
    },
    {
      "name": "test_multiple_challenges_active",
      "input": [
        { "challengeStatus": "active" },
        { "challengeStatus": "active" }
      ],
      "output": [
        { "checkpointScreeningVisible": true, "screeningPhasesVisible": true },
        { "checkpointScreeningVisible": true, "screeningPhasesVisible": true }
      ],
      "notes": "Validates that multiple active challenges show checkpoint screening and phases."
    },
    {
      "name": "test_edge_case_no_challenges",
      "input": [],
      "output": [],
      "notes": "Tests behavior when there are no challenges to display."
    },
    {
      "name": "test_edge_case_invalid_status",
      "input": {
        "challengeStatus": "unknown"
      },
      "output": {
        "checkpointScreeningVisible": false,
        "screeningPhasesVisible": false
      },
      "notes": "Checks that an invalid challenge status does not show checkpoint screening or phases."
    },
    {
      "name": "test_transition_from_inactive_to_active",
      "input": {
        "initialStatus": "inactive",
        "newStatus": "active"
      },
      "output": {
        "checkpointScreeningVisible": true,
        "screeningPhasesVisible": true
      },
      "notes": "Validates the transition of a challenge from inactive to active correctly updates visibility."
    },
    {
      "name": "test_transition_from_active_to_inactive",
      "input": {
        "initialStatus": "active",
        "newStatus": "inactive"
      },
      "output": {
        "checkpointScreeningVisible": false,
        "screeningPhasesVisible": false
      },
      "notes": "Checks that transitioning a challenge from active to inactive hides checkpoint screening and phases."
    }
  ],
  "assumptions": "The challenge status can only be 'active' or 'inactive'.",
  "notes": "Ensure to test both the visibility of checkpoint screening and screening phases based on challenge status."
}
